use std::sync::Mutex;

pub fn double_lock(m: &Mutex<i32>) -> i32 {
    let g1 = m.lock().unwrap();
    *g1 + *g1
}

use std::borrow::Cow;

pub fn normalise(input: &str) -> Cow<'_, str> {
    if input.contains('A') {
        Cow::Owned(input.replace('A', "a"))
    } else {
        Cow::Borrowed(input)
    }
}

use std::sync::Arc;

pub fn bump(a: &mut Arc<Vec<i32>>) {
    Arc::make_mut(a).push(42);
}

use std::cell::RefCell;

pub fn aliased_borrow(c: &RefCell<i32>) {
    let r1 = c.borrow();
    drop(r1);
    let r2 = c.borrow_mut();
    drop(r2);
}

#[must_use]
pub fn checked_add(a: i32, b: i32) -> Option<i32> {
    a.checked_add(b)
